import { daemonRoot, extensionBundle } from "./targets.mjs";

// The manifest allowlist vsce reads. `package.json` is generated by
// createStagedManifest rather than copied, so it appears here and nowhere in
// `copies`. `daemonRoot/` is a directory in the allowlist but narrows to one
// target on disk.
const manifestFilesFor = (manifest) => [
  extensionBundle,
  `${daemonRoot}/`,
  "cli/",
  "README.md",
  "LICENSE",
  "package.json",
  ...(manifest.icon ? [manifest.icon] : []),
];

// One source of truth for what ships in the VSIX, in the two shapes its two
// consumers need: `manifestFiles` for the staged package.json, `copies` for the
// staging directory. They cannot disagree, so nothing has to test that they do.
export const stagedPackageLayout = ({ manifest, target }) => ({
  manifestFiles: manifestFilesFor(manifest),
  copies: [
    { source: "README.md", destination: "README.md" },
    { source: "LICENSE", destination: "LICENSE" },
    { source: "cli", destination: "cli" },
    { source: extensionBundle, destination: extensionBundle },
    { source: `${daemonRoot}/${target}`, destination: `${daemonRoot}/${target}` },
    ...(manifest.icon ? [{ source: manifest.icon, destination: manifest.icon }] : []),
  ],
});

export const createStagedManifest = ({ manifest }) => ({
  ...manifest,
  devDependencies: undefined,
  files: manifestFilesFor(manifest),
  scripts: undefined,
});
